// Import necessary modules
import React, { useEffect } from 'react';
import { View } from 'react-native';
import Biometrics from 'react-native-biometrics';
import { useNavigation } from '@react-navigation/native';
import AsyncStorage from '@react-native-community/async-storage';
import LoginScreen from './LoginScreen';

const BiometricAuth = () => {
  const navigation = useNavigation();

  useEffect(() => {
    checkAuthentication();
  }, []);

  const checkAuthentication = async () => {
    try {
      const authFlag = await AsyncStorage.getItem('authenticated');
      if (authFlag === 'true') {
        navigation.navigate('Home');
      } else {
        promptForBiometrics();
      }
    } catch (error) {
      console.log(error);
    }
  };

  const promptForBiometrics = () => {
    Biometrics.isSensorAvailable()
      .then(biometricType => {
        if (biometricType === Biometrics.TouchID || biometricType === Biometrics.FaceID) {
          Biometrics.createSignature('Confirm fingerprint', 'Sign in to your account')
            .then(async () => {
              await AsyncStorage.setItem('authenticated', 'true');
              navigation.navigate('Home');
            })
            .catch(() => {
              navigation.navigate('LoginScreen');
            });
        } else {
          navigation.navigate('LoginScreen');
        }
      })
      .catch(() => {
          navigation.navigate('LoginScreen');
      });
  };

  return <View />;
};

export default BiometricAuth;